def set_cors_headers(response):
    """Set CORS headers on response"""
    response.headers.set('Access-Control-Allow-Origin', '*')
    response.headers.set('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS')
    response.headers.set('Access-Control-Allow-Headers', 'Content-Type, Authorization, X-Requested-With')
    response.headers.set('Access-Control-Max-Age', '3600')
    return response

def validate_request_size(request: Request, max_size_mb=10):
    """Validate request size to prevent DoS attacks"""
    content_length = request.content_length
    if content_length and content_length > max_size_mb * 1024 * 1024:
        return False
    return True

def sanitize_input(data):
    """Basic input sanitization"""
    if isinstance(data, dict):
        return {k: sanitize_input(v) for k, v in data.items()}
    elif isinstance(data, list):
        return [sanitize_input(item) for item in data]
    elif isinstance(data, str):
        # Remove potential script tags and limit length
        sanitized = data.replace('<', '&lt;').replace('>', '&gt;')
        return sanitized[:10000]  # Limit string length
    return data

def validate_json(request: Request):
    """Safely parse and validate JSON"""
    try:
        if request.content_length == 0:
            return {}
        data = request.get_json(silent=True)
        if data is None:
            return None
        return sanitize_input(data)
    except Exception:
        return None

